import React, { useState, useEffect } from 'react';
import { Cpu, Plus, Play, Download, BarChart3, Settings, Home, User, Keyboard, Zap } from 'lucide-react';
import ProcessInput from './components/ProcessInput';
import GanttChart from './components/GanttChart';
import PerformanceMetrics from './components/PerformanceMetrics';
import AlgorithmSelector from './components/AlgorithmSelector';
import TypingTutor from './components/TypingTutor';
import TypingGame from './components/TypingGame';
import TypingAnimation from './components/TypingAnimation';
import { schedulingAlgorithms } from './utils/schedulingAlgorithms';
import './App.css';

function App() {
  const [processes, setProcesses] = useState([]);
  const [selectedAlgorithm, setSelectedAlgorithm] = useState('fcfs');
  const [timeQuantum, setTimeQuantum] = useState(2);
  const [ganttData, setGanttData] = useState([]);
  const [performanceData, setPerformanceData] = useState(null);
  const [currentView, setCurrentView] = useState('home');
  const [isAnimating, setIsAnimating] = useState(false);
  const [stepMode, setStepMode] = useState(false);
  const [currentStep, setCurrentStep] = useState(0);
  const [typingMode, setTypingMode] = useState('tutor'); // 'tutor' or 'game'

  useEffect(() => {
    // Always use dark/cyber mode
    document.documentElement.classList.add('dark');
  }, []);

  const runSimulation = () => {
    if (processes.length === 0) return;

    const algorithm = schedulingAlgorithms[selectedAlgorithm];
    const result = algorithm(processes, timeQuantum);

    setGanttData(result.ganttChart);
    setPerformanceData(result.metrics);

    if (stepMode) {
      setIsAnimating(true);
      animateSteps(result.ganttChart);
    }
  };

  const animateSteps = (ganttChart) => {
    let step = 0;
    const interval = setInterval(() => {
      if (step >= ganttChart.length) {
        clearInterval(interval);
        setIsAnimating(false);
        return;
      }
      setCurrentStep(step);
      step++;
    }, 1000);
  };

  const exportResults = () => {
    const results = {
      algorithm: selectedAlgorithm,
      timeQuantum: selectedAlgorithm === 'roundRobin' ? timeQuantum : null,
      processes: processes,
      ganttChart: ganttData,
      performanceMetrics: performanceData
    };

    const dataStr = JSON.stringify(results, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);

    const exportFileDefaultName = `cpu-scheduling-results-${Date.now()}.json`;

    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', exportFileDefaultName);
    linkElement.click();
  };

  const renderMobileView = () => (
    <div className="min-h-screen cyber-bg relative">
      <div className="relative z-10 pb-20">
        <header className="bg-black/50 backdrop-blur-md border-b border-cyan-500/30">
          <div className="px-4 py-3 flex items-center justify-between">
            <div className="flex items-center space-x-2">
              <Cpu className="w-6 h-6 text-cyan-400 cyber-glow" />
              <h1 className="text-lg font-bold cyber-text">CPU_SCHEDULER</h1>
            </div>
            <div className="flex items-center space-x-2">
              <TypingAnimation 
                texts={["SYSTEM_ONLINE", "READY", "PROCESSING"]} 
                speed={150}
                cursorType="rainbow"
                className="text-xs cyber-text-cyan mr-2"
              />
            </div>
          </div>
        </header>

        <main className="p-4 space-y-4">
          {currentView === 'home' && (
            <>
              <div className="terminal">
                <h2 className="cyber-title mb-4">SYSTEM_CONTROL</h2>
                <AlgorithmSelector
                  selectedAlgorithm={selectedAlgorithm}
                  setSelectedAlgorithm={setSelectedAlgorithm}
                  timeQuantum={timeQuantum}
                  setTimeQuantum={setTimeQuantum}
                />
              </div>

              <div className="cyber-card p-4">
                <h3 className="cyber-text font-bold mb-3">PROCESS_INPUT</h3>
                <ProcessInput
                  processes={processes}
                  setProcesses={setProcesses}
                />
              </div>

              <div className="flex space-x-2">
                <button
                  onClick={runSimulation}
                  disabled={processes.length === 0}
                  className="flex-1 cyber-button px-4 py-3 rounded-lg font-medium disabled:opacity-50 flex items-center justify-center space-x-2"
                >
                  <Play className="w-4 h-4" />
                  <span>EXECUTE</span>
                </button>

                <button
                  onClick={() => setStepMode(!stepMode)}
                  className={`px-4 py-3 rounded-lg font-medium border ${stepMode ? 'cyber-button' : 'border-cyan-500/50 text-cyan-400'}`}
                >
                  {stepMode ? 'STEP_ON' : 'STEP_OFF'}
                </button>
              </div>

              {ganttData.length > 0 && (
                <div className="cyber-card p-4">
                  <h3 className="cyber-text font-bold mb-3">GANNT_VISUALIZATION</h3>
                  <GanttChart
                    data={ganttData}
                    isAnimating={isAnimating}
                    currentStep={currentStep}
                    stepMode={stepMode}
                  />
                </div>
              )}

              {performanceData && (
                <div className="cyber-card p-4">
                  <h3 className="cyber-text font-bold mb-3">PERFORMANCE_METRICS</h3>
                  <PerformanceMetrics data={performanceData} />
                </div>
              )}

              {performanceData && (
                <button
                  onClick={exportResults}
                  className="w-full cyber-button px-4 py-3 rounded-lg font-medium flex items-center justify-center space-x-2"
                >
                  <Download className="w-4 h-4" />
                  <span>EXPORT_DATA</span>
                </button>
              )}
            </>
          )}

          {currentView === 'typing' && (
            <>
              <div className="terminal">
                <h2 className="cyber-title mb-4">TYPE_TRAINING</h2>
                <div className="flex space-x-2 mb-4">
                  <button
                    onClick={() => setTypingMode('tutor')}
                    className={`flex-1 px-4 py-2 rounded-lg font-medium border ${typingMode === 'tutor' ? 'cyber-button' : 'border-cyan-500/50 text-cyan-400'}`}
                  >
                    <Keyboard className="w-4 h-4 inline mr-2" />
                    TUTOR_MODE
                  </button>
                  <button
                    onClick={() => setTypingMode('game')}
                    className={`flex-1 px-4 py-2 rounded-lg font-medium border ${typingMode === 'game' ? 'cyber-button' : 'border-cyan-500/50 text-cyan-400'}`}
                  >
                    <Zap className="w-4 h-4 inline mr-2" />
                    GAME_MODE
                  </button>
                </div>
              </div>

              <div className="cyber-card">
                {typingMode === 'tutor' ? <TypingTutor /> : <TypingGame />}
              </div>
            </>
          )}

          {currentView === 'analytics' && (
            <div className="terminal text-center py-20">
              <BarChart3 className="w-16 h-16 mx-auto cyber-text-cyan cyber-float mb-4" />
              <h2 className="cyber-title mb-2">Analytics Module</h2>
              <TypingAnimation 
                texts={["Comparing Algorithms", "Analyzing Performance", "Generating Reports"]} 
                speed={100}
                cursorType="glow"
                className="cyber-text-magenta"
              />
              <div className="mt-4">
                <span className="cyber-cursor-terminal cursor-glow"></span>
              </div>
            </div>
          )}

          {currentView === 'settings' && (
            <div className="terminal text-center py-20">
              <Settings className="w-16 h-16 mx-auto basic-text mb-4" />
              <h2 className="basic-title mb-2">System Settings</h2>
              <p className="basic-text">Configure simulation parameters</p>
            </div>
          )}
        </main>

        <nav className="mobile-bottom-nav">
          <button
            onClick={() => setCurrentView('home')}
            className={`p-2 ${currentView === 'home' ? 'active' : ''}`}
          >
            <Home className="w-6 h-6" />
          </button>
          <button
            onClick={() => setCurrentView('typing')}
            className={`p-2 ${currentView === 'typing' ? 'active' : ''}`}
          >
            <Keyboard className="w-6 h-6" />
          </button>
          <button
            onClick={() => setCurrentView('analytics')}
            className={`p-2 ${currentView === 'analytics' ? 'active' : ''}`}
          >
            <BarChart3 className="w-6 h-6" />
          </button>
          <button
            onClick={() => setCurrentView('settings')}
            className={`p-2 ${currentView === 'settings' ? 'active' : ''}`}
          >
            <Settings className="w-6 h-6" />
          </button>
        </nav>
      </div>
    </div>
  );

  const renderDesktopView = () => (
    <div className="min-h-screen cyber-bg relative">
      <div className="relative z-10">
        <header className="desktop-nav bg-black/50 backdrop-blur-md border-b border-cyan-500/30">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="flex items-center justify-between h-16">
              <div className="flex items-center space-x-8">
                <div className="flex items-center space-x-2">
                  <Cpu className="w-8 h-8 text-cyan-400 cyber-glow" />
                  <h1 className="text-2xl font-bold cyber-text">CPU_SCHEDULER</h1>
                </div>
                <nav className="hidden md:flex space-x-6">
                  <button className="cyber-text-cyan hover:text-cyan-300 font-medium">Home</button>
                  <button className="cyber-text-cyan hover:text-cyan-300 font-medium">Typing</button>
                  <button className="cyber-text-cyan hover:text-cyan-300 font-medium">Analytics</button>
                  <button className="cyber-text-cyan hover:text-cyan-300 font-medium">Documentation</button>
                </nav>
              </div>
              <div className="flex items-center space-x-4">
                <TypingAnimation 
                  texts={["SYSTEM_ACTIVE", "MONITORING", "OPTIMIZED"]} 
                  speed={120}
                  cursorType="glow"
                  className="text-sm cyber-text-magenta"
                />
              </div>
            </div>
          </div>
        </header>

        <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
          <div className="flex space-x-1 mb-6">
            <button
              onClick={() => setCurrentView('home')}
              className={`px-4 py-2 rounded-lg font-medium border ${currentView === 'home' ? 'basic-button' : 'border-gray-300 text-gray-700'}`}
            >
              CPU Simulator
            </button>
            <button
              onClick={() => setCurrentView('typing')}
              className={`px-4 py-2 rounded-lg font-medium border ${currentView === 'typing' ? 'basic-button' : 'border-gray-300 text-gray-700'}`}
            >
              Typing Practice
            </button>
          </div>

          {currentView === 'home' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1 space-y-6">
                <div className="cyber-card p-6">
                  <h3 className="cyber-title mb-4">Algorithm Control</h3>
                  <AlgorithmSelector
                    selectedAlgorithm={selectedAlgorithm}
                    setSelectedAlgorithm={setSelectedAlgorithm}
                    timeQuantum={timeQuantum}
                    setTimeQuantum={setTimeQuantum}
                  />
                </div>

                <div className="cyber-card p-6">
                  <h3 className="cyber-text font-bold mb-3">Process Input</h3>
                  <ProcessInput
                    processes={processes}
                    setProcesses={setProcesses}
                  />
                </div>

                <div className="cyber-card p-6">
                  <h3 className="cyber-text font-bold mb-4">Simulation Control</h3>
                  <div className="flex space-x-2">
              <button
                onClick={runSimulation}
                disabled={processes.length === 0}
                className="flex-1 basic-button px-4 py-3 rounded-lg font-medium disabled:opacity-50 flex items-center justify-center space-x-2"
              >
                <Play className="w-4 h-4" />
                <span>Run Simulation</span>
              </button>

              <button
                onClick={() => setStepMode(!stepMode)}
                className={`flex-1 px-4 py-2 rounded-lg font-medium border ${stepMode ? 'basic-button' : 'border-gray-300 text-gray-700'}`}
              >
                {stepMode ? 'Step Mode ON' : 'Step Mode OFF'}
              </button>

              {performanceData && (
                <button
                  onClick={exportResults}
                  className="flex-1 basic-button px-4 py-2 rounded-lg font-medium flex items-center justify-center space-x-1"
                >
                  <Download className="w-4 h-4" />
                  <span>Export</span>
                </button>
              )}
            </div>
                </div>
              </div>

              <div className="lg:col-span-2 space-y-6">
                {ganttData.length > 0 && (
                  <div className="cyber-card p-6">
                    <h3 className="cyber-text font-bold mb-4">GANNT_VISUALIZATION</h3>
                    <GanttChart
                      data={ganttData}
                      isAnimating={isAnimating}
                      currentStep={currentStep}
                      stepMode={stepMode}
                    />
                  </div>
                )}

                {performanceData && (
                  <div className="cyber-card p-6">
                    <h3 className="cyber-text font-bold mb-4">PERFORMANCE_METRICS</h3>
                    <PerformanceMetrics data={performanceData} />
                  </div>
                )}

                {ganttData.length === 0 && (
                  <div className="cyber-card p-12 text-center">
                    <Cpu className="w-16 h-16 mx-auto cyber-text-cyan cyber-float mb-4" />
                    <h3 className="cyber-title mb-2">Ready to Simulate</h3>
                    <p className="cyber-text">Add processes and select an algorithm to begin the simulation</p>
                  </div>
                )}
              </div>
            </div>
          )}

          {currentView === 'typing' && (
            <div>
              <div className="flex space-x-2 mb-6">
              <button
                onClick={() => setTypingMode('tutor')}
                className={`flex-1 px-4 py-2 rounded-lg font-medium border ${typingMode === 'tutor' ? 'basic-button' : 'border-gray-300 text-gray-700'}`}
              >
                <Keyboard className="w-4 h-4 inline mr-2" />
                Typing Tutor
              </button>
              <button
                onClick={() => setTypingMode('game')}
                className={`flex-1 px-4 py-2 rounded-lg font-medium border ${typingMode === 'game' ? 'basic-button' : 'border-gray-300 text-gray-700'}`}
              >
                <Zap className="w-4 h-4 inline mr-2" />
                Typing Game
              </button>
            </div>

              <div className="cyber-card">
                {typingMode === 'tutor' ? <TypingTutor /> : <TypingGame />}
              </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );

  return (
    <div className="App">
      <div className="md:hidden">
        {renderMobileView()}
      </div>
      <div className="hidden md:block">
        {renderDesktopView()}
      </div>
    </div>
  );
}

export default App;
